  name_fr         VARCHAR(100),
  name_ar         VARCHAR(100),
  category        item_category NOT NULL DEFAULT 'other',
  popularity      INTEGER NOT NULL DEFAULT 0         -- Higher = more common
);

CREATE INDEX idx_common_items_pop ON common_items (popularity DESC);
CREATE INDEX idx_common_items_name ON common_items (name_en);

