-- ────────────────────────────────────────────────────────────────────────────
-- CLEANUP JOBS (to be run via cron or pg_cron)
-- ────────────────────────────────────────────────────────────────────────────

-- Delete expired, unused pairing tokens (run hourly)
-- DELETE FROM pairing_tokens WHERE expires_at < NOW() AND used_at IS NULL;

-- Hard-delete soft-deleted items older than 30 days (run daily)
-- DELETE FROM items WHERE deleted_at IS NOT NULL AND deleted_at < NOW() - INTERVAL '30 days';

-- Archive pairs inactive for 90 days (run weekly)
-- UPDATE pairs SET status = 'archived', archived_at = NOW()
-- WHERE status = 'active'
-- AND NOT EXISTS (
--   SELECT 1 FROM items i
--   JOIN lists l ON l.id = i.list_id
--   WHERE l.pair_id = pairs.id AND i.updated_at > NOW() - INTERVAL '90 days'
-- );

-- Purge synced queue entries older than 7 days (run daily)
-- DELETE FROM sync_queue WHERE synced_at IS NOT NULL AND synced_at < NOW() - INTERVAL '7 days';
